<?php
namespace App\Http\Controllers; use App\Models\User; use Illuminate\Http\{JsonResponse,Request,Response}; use Illuminate\Support\Facades\Hash;
class AuthController extends Controller { private function safe(User $u):array{return['id'=>$u->id,'name'=>$u->name,'email'=>$u->email,'role'=>$u->role,'is_active'=>$u->is_active,'must_change_password'=>$u->must_change_password,'effective_permissions'=>$u->getEffectivePermissions(),'permission_overrides'=>$u->getPermissionOverrides()];} public function login(Request $r):JsonResponse{$d=$r->validate(['email'=>['required','email'],'password'=>['required','string']]);$u=User::where('email',$d['email'])->first();if(!$u||!$u->is_active||!Hash::check($d['password'],$u->password))return response()->json(['message'=>'Invalid credentials.'],401);$u->update(['last_login_at'=>now()]);return response()->json(['token'=>$u->createToken('dashboard')->plainTextToken,'user'=>$this->safe($u)]);} public function me(Request $r):JsonResponse{return response()->json(['user'=>$this->safe($r->user())]);} public function logout(Request $r):Response{$r->user()->currentAccessToken()?->delete();return response()->noContent();}}
